import { 
  useRef,
  useEffect 
} from 'react'

import {
  useFocusRing, 
  useSwitch,
  VisuallyHidden,
  useField
} from 'react-aria'

import { useToggleState } from 'react-stately'

import { 
  Description,
  Label 
} from '../../base'

/**
 * @see https://react-spectrum.adobe.com/react-aria/useSwitch.html
 */

const Switch = props => {

  const state = useToggleState(props)
  const ref = useRef()

  const { inputProps } = useSwitch({
    ...props,
    children: props.label ?? ''
  }, state, ref)
  const { focusProps } = useFocusRing()

  /**
   * useSwitch does not return label and description props directly
   */
  const { 
    labelProps, 
    fieldProps,
    descriptionProps 
  } = useField(props)

  useEffect(() => props.onChange && props.onChange(state.isSelected), [state.isSelected])
  useEffect(() => {
    if( props.value !== state.isSelected )  state.setSelected(props.value)
  }, [props.value])

  return(
    <div className="tf-switch">
      { props.label &&
        <Label labelProps={ labelProps } parent={ props }>
          { props.label }
        </Label> }
        <label className="tf-switch-label">
          <VisuallyHidden>
            <input 
              { ...fieldProps }
              { ...inputProps } 
              { ...focusProps }
              ref={ ref } 
              name="" 
            />
          </VisuallyHidden>
          <div className={ `tf-switch-element${state.isSelected ? '-selected' : '' }` } aria-hidden="true">
            <span></span>
          </div>
        </label>
      { props.description &&
        <Description descriptionProps={ descriptionProps } parent={ props }>
          { props.description }
        </Description> }
    </div>
  )
}

export default Switch

import {
  forwardRef,
  useRef
} from 'react'

import { Checkbox as TuiCheckbox, Field } from '@tangible/ui'

export interface FieldsCheckboxProps {
  value?: boolean | '1' | '0'
  onChange?: (value: boolean) => void
  label?: string
  labelVisuallyHidden?: boolean
  description?: string
  descriptionVisuallyHidden?: boolean
  isDisabled?: boolean
  isRequired?: boolean
  name?: string
  className?: string
}

const Checkbox = forwardRef<HTMLInputElement, FieldsCheckboxProps>((props, ref) => {

  const {
    value,
    onChange,
    label,
    labelVisuallyHidden,
    description,
    descriptionVisuallyHidden,
    isDisabled,
    isRequired,
    name,
    className,
  } = props

  const warnedRef = useRef(false)
  if (!warnedRef.current && !label) {
    warnedRef.current = true
    console.warn('Checkbox: Missing label. Provide a label prop for accessibility.')
  }

  /**
   * Derive boolean checked state directly from the value prop.
   * When value is provided, TUI Checkbox is fully controlled — no local state needed.
   * External changes (e.g. repeater bulk-select) are reflected automatically.
   */
  const boolValue = value === '1' || value === true
  const controlledProps = value !== undefined
    ? { checked: boolValue }
    : { defaultChecked: false }

  const labelContent = label
    ? labelVisuallyHidden
      ? <span className="tui-visually-hidden">{label}</span>
      : label
    : undefined

  return (
    <div className="tf-checkbox">
      <Field
        className={className}
        required={Boolean(isRequired)}
        disabled={Boolean(isDisabled)}
      >
        <TuiCheckbox
          ref={ref}
          label={labelContent}
          {...controlledProps}
          disabled={Boolean(isDisabled)}
          onCheckedChange={nextChecked => {
            if (onChange) onChange(nextChecked)
          }}
        />
        <input type="hidden" name={name ?? ''} value={boolValue ? '1' : '0'} />
        {description && (
          <Field.HelperText className={descriptionVisuallyHidden ? 'tui-visually-hidden' : undefined}>
            {description}
          </Field.HelperText>
        )}
      </Field>
    </div>
  )
})

export default Checkbox

