const evaluateCondition = condition => {

  const partResults = []  

  if (condition.length === 0) return true

  for (const lho in condition) {

    const parts = condition[lho]

    // Relations
    if (['_and', '_or'].includes(lho)) {

      const partResultsInner = parts.map(evaluateCondition)

      if( partResultsInner.length === 0 ) {
        partResults.push(false)
        continue;
      }

      switch (lho) {
        case '_or':
          partResults.push(partResultsInner.filter(Boolean).length > 0)
          break;
        case '_and':
          partResults.push(partResultsInner.length === partResultsInner.filter(Boolean).length)
          break;
      }
      continue;
    }

    // Comparison.
    Object.entries(parts).forEach(([op, rho]) => {
      switch (op) {
        case '_eq':
          partResults.push(lho == rho)
          break;
        case '_neq':
          partResults.push(lho != rho)
          break;
        case '_lt':
          partResults.push(lho < rho)
          break;
        case '_gt':
          partResults.push(lho > rho)
          break;
        case '_lte':
          partResults.push(lho <= rho)
          break;
        case '_gte':
          partResults.push(lho >= rho)
          break;
        case '_in':
          partResults.push(rho.includes(lho))
          break;
        case '_nin':
          partResults.push(!rho.includes(lho))
          break;
        case '_contains':
          partResults.push(lho.includes(rho))
          break;
        case '_ncontains':
          partResults.push(!lho.includes(rho))
          break;
        case '_re':
          partResults.push(new RegExp(rho).test(lho))
          break;
        default:
          partResults.push(false)
      }
    })
  }

  return partResults.length > 0 && partResults.length === partResults.filter(Boolean).length
}

export {
  evaluateCondition
}

import { 
  useState,
  useEffect,
  useMemo
} from 'react'

import { 
  evaluateFieldVisibility,
  getTriggerFields
} from '../../visibility/'

import { addEventListener } from '../../events'

const VisibilityWrapper = ({
  visibility,
  data,
  ...props
}) => {

  const [isVisible, setVisibility] = useState(false) // False until we evaluate conditions

  const evaluateVisibility = () => {

    if( ! visibility.condition ) {
      setVisibility(true)
      return;
    } 

    // The default callback looks only for a value in other defined fields, but we can overwrite it if needed
    const getValue = data.getValue ?? control.getValue
    const result = evaluateFieldVisibility(visibility.condition, getValue)

    setVisibility( visibility.action !== 'hide' ? result : ! result )
  }

  useEffect(() => {

    evaluateVisibility() // Initial visibility

    if( ! visibility.condition || ! triggerFields ) {
      return;
    } 

    /**
     * Trigger visibility re-evaluation on
     */
    addEventListener('valueChange', field => {

      // We rely on data.watcher for subfield changes (@see below)
      if( field.props?.itemType === 'subfield' ) return;

      // Avoid unnecessary evaluations
      if( ! triggerFields.includes(field.name) ) return;

      setTimeout(evaluateVisibility)
    })

    /**
     * The visibility watcher is an additional callback we can use to evaluate
     *  
     * It is currently used to watch changes in subfields (repeaters, field-groups)
     */
    if( data.watcher ) {
      data.watcher(fieldName => {
        // Avoid unnecessary evaluations
        if( triggerFields.includes(fieldName) ) evaluateVisibility()
      })
    }

    /**
     * Global event to manually re-evaluate all the visibility conditions
     */
    addEventListener('evaluateVisibility', () => evaluateVisibility())
  }, [])

  /**
   * Determine for which fields a value change should trigger a re-evaluation of 
   * the visibility conditions (see visibility.watcher)
   */
  const triggerFields = useMemo(() => (
    visibility.condition ? getTriggerFields(visibility.condition) : false
  ), [])

  return isVisible ? props.children : <></>
}

export default VisibilityWrapper

import Control from '../../../Control'
import Element from '../../../Element'
import types from '../../../types'

const FieldGroupItem = ({
  config,
  values,
  onChange,
  data
}) => {

  const elements = Object.keys(types._types.element)
  const isElement = elements.includes(config.type ?? '')

  const Component = isElement ? Element : Control
  const controlProps = ! isElement
    ? {
      value    : values[ config.name ] ?? '',
      onChange : onChange
    } : {}

  return(
    <Component
      itemType={ isElement ? 'subelement' : 'subfield' }
      visibility={{
        action    : config.condition?.action ?? 'show',
        condition : config.condition?.condition ?? false
      }}
      data={ data }
      { ...config }
      { ...controlProps }
    />
  )
}

