import {
  useMemo,
  useEffect,
  useCallback
} from 'react'

import {
  addEventListener,
  removeEventListener
} from '../../events'

import {
  getDependentFields,
  mergeDependentProps
} from './utils'

const DependendWrapper = ({
  itemProps,
  refresh,
  data,
  children
}) => {

  const childProps =  Object.assign({}, itemProps)

  delete childProps.value
  delete childProps.onChange
  delete childProps.class
  delete childProps.wrapper

  /**
   * Store fields that needs to be watched in order to update dependent values accordingly
   */
  const dependentFields = useMemo(() => (
    itemProps.dependent
      ? Object.assign({}, getDependentFields(itemProps))
      : false
  ), [])

  const maybeUpdateProps = (fieldName) => {

    if( ! itemProps.dependent || ! dependentFields ) return;
    if( ! Object.keys(dependentFields).includes(fieldName) ) return;

    refresh()
  }

  const dependentWatcher = useCallback(field => {

    // Only regular fields (event is also triggerd for repeater subfields)
    if( field.props?.itemType === 'subfield' ) return;

    maybeUpdateProps(field.name)
  }, [])

  useEffect(() => {
    const callback = addEventListener('valueChange', dependentWatcher)
    return () => removeEventListener('valueChange', callback)
  }, [dependentWatcher])

  /**
   * The data watcher is an additional callback we can use to watch changes
   *
   * It is currently used to watch changes in subfields (repeaters, field-groups)
   */
  useEffect(() => {
    if( data.watcher ) {
      data.watcher(fieldName => {
        maybeUpdateProps(fieldName)
      })
    }
  }, [dependentWatcher])

  const formatedProps = useMemo(() => (
    mergeDependentProps(
      childProps,
      dependentFields,
      data.getValue
    )
  ), [])

  return children(formatedProps)
}

export default DependendWrapper

import { 
  useState,
  useEffect,
  Fragment
} from 'react'

import { 
  addEventListener,
  removeEventListener
} from '../../events'

/**
 * Handle re-render of a control, it is used in two cases:
 * - Dependent values (force re-render when dependent field value change)
 * - Value update from outside of the control
 * 
 * Could we use useContext for this?
 */
const RenderWrapper = ({ 
  children,
  itemType, 
  setValue = false,
  name
}) => {

  const [key, setKey] = useState(0)

  const refreshRender = () => setKey(key + 1)

  const fieldValueChanged = field => {
    if( ! name || name !== field.name ) return;
    refreshRender()
    if( setValue ) setValue(field.value)
  }

  const maybeRerender = fieldName => {
    fieldName === name ? refreshRender() : null
  }

  useEffect(() => {

    // Only support forced refresh for regular field for now (no subfields)
    if( itemType !== 'field' ) return;

    const callbackValuechanged = addEventListener('_refreshFieldValue', fieldValueChanged)
    const callbackRerender = addEventListener('_fieldRerender', maybeRerender)

    return () => {
      removeEventListener('_refreshFieldValue', callbackValuechanged)
      removeEventListener('_fieldRerender', callbackRerender)
    }
  }, [key])

  return(
    <Fragment key={ key }>
      { children(refreshRender) }
    </Fragment>
  )
}

export default RenderWrapper

import {
  useState,
  useEffect
} from 'react'

import Switch from './Switch'

const SwitchField = props => {

  const valueOn = props.valueOn ?? 'on' 
  const valueOff = props.valueOff ?? 'off'

  const [value, setValue] = useState(props.value ?? valueOff)

  useEffect(() => props.onChange && props.onChange(value), [value])
  useEffect(() => {
    if( ! [valueOn, valueOff].includes(props.value) ) return;
    if( props.value !== value ) setValue(props.value)
  }, [props.value])

  return(
    <>
      <input type="hidden" name={ props.name ?? ''} value={ value } />
      <Switch
        label={ props.label ?? '' }
        labelVisuallyHidden={ props.labelVisuallyHidden ?? false }
        description={ props.description ?? '' }
        value={ value === valueOn } 
        onChange={ switchValue => setValue(switchValue ? valueOn : valueOff )} 
      />
    </>
  )
}

export default SwitchField

